import { Link } from 'react-router-dom';
import { Carousel } from 'react-responsive-carousel';
import 'react-responsive-carousel/lib/styles/carousel.min.css';
import PropTypes from 'prop-types';
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faStar } from "@fortawesome/free-solid-svg-icons";
import './Testimonials.scss';
import testimonials from '../../assets/data/testimonials-data';
import { useAnimateOnScroll } from "../../hooks/useAnimateOnScroll";

const Star = () => <FontAwesomeIcon icon={faStar} aria-hidden="true" />;

const TESTIMONIAL_SIGNALS = [
  "Warm, local communication",
  "Easy around hotel schedules",
  "Relaxed pacing guests remember",
];

const Stars = ({ count }) => {
  const stars = Array.from({ length: count }, (_, i) => <Star key={i} />);
  return <div className="testimonial__stars">{stars}</div>;
};

Stars.propTypes = {
  count: PropTypes.number.isRequired,
};

const Testimonial = ({ imgSrc, name, review, starCount }) => {
  return (
    <div className="testimonial">
      <div className="testimonial__header">
        <div className="testimonial__avatar">
          <img src={imgSrc} alt={`${name}'s testimonial`} className="testimonial__image" />
        </div>
        <div className="testimonial__name-stars">
          <p className="testimonial__name">{name}</p>
          <Stars count={starCount} />
        </div>
      </div>
      <span className="testimonial__quote-label">Guest note</span>
      <div className="testimonial__review">
        <span>{review}</span>
      </div>
    </div>
  );
};

Testimonial.propTypes = {
  imgSrc: PropTypes.string.isRequired,
  name: PropTypes.string.isRequired,
  review: PropTypes.string.isRequired,
  starCount: PropTypes.number.isRequired,
};

const Testimonials = () => {
  const [sectionRef, isVisible] = useAnimateOnScroll({
    threshold: 0.1,
    rootMargin: "50px",
  });
  const testimonialPoints = [
    "Guests mention easy communication and warm local guidance.",
    "Each day can be customized around your hotel base and schedule.",
    "The experience stays relaxed even when the itinerary is full.",
  ];

  return (
    <section
      ref={sectionRef}
      className={`testimonials ${isVisible ? "animate" : ""}`}
    >
      <div className="testimonials__intro">
        <div className="testimonials__heading">
          <p className="testimonials__eyebrow">Guest notes</p>
          <h2 className="testimonials__title">Stories from the island</h2>
        </div>
        <p className="testimonials__description">
          The details guests remember most tend to be simple: calm planning, genuine local hosts,
          and days that feel thoughtfully paced from start to finish.
        </p>
      </div>
      <div className="testimonials__signals" aria-label="What guests often mention">
        {TESTIMONIAL_SIGNALS.map((signal) => (
          <span key={signal}>{signal}</span>
        ))}
      </div>

      <div className="testimonials__layout">
        <aside className="testimonials__aside">
          <div className="testimonials__aside-card">
            <span className="testimonials__aside-label">Why it feels easy</span>
            <p className="testimonials__aside-copy">
              The same themes come back again and again after a trip: calm planning,
              friendly guidance, and days that feel well-shaped instead of rushed.
            </p>
            <ul className="testimonials__points">
              {testimonialPoints.map((point) => (
                <li key={point}>{point}</li>
              ))}
            </ul>
            <Link to="/booking" className="testimonials__button">
              Start Your Plan
            </Link>
          </div>
        </aside>

        <div className="testimonials__carousel-panel">
          <Carousel
            showArrows={false}
            infiniteLoop={true}
            showThumbs={false}
            showStatus={false}
            showIndicators={false}
            autoPlay={true}
            interval={10000}
            className="testimonials__carousel"
          >
            {testimonials.map((testimonial, index) => (
              <Testimonial key={index} {...testimonial} />
            ))}
          </Carousel>
        </div>
      </div>
    </section>
  );
};

export default Testimonials;
